export function initialize(sentinel, dotNetRef) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetRef.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '0px 0px 250px 0px' });

    observer.observe(sentinel);
    sentinel.__infiniteScrollObserver = observer;
}

export function dispose(sentinel) {
    if (sentinel?.__infiniteScrollObserver) {
        sentinel.__infiniteScrollObserver.disconnect();
        delete sentinel.__infiniteScrollObserver;
    }
}

@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container" style="overflow-y:auto; max-height:80vh;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel"
             style="display:flex; justify-content:center; padding:1rem;">
            @if (_isLoading)
            {
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private bool _initialized;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    [Inject]
    private IJSRuntime JS { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");
            _dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && _module is not null)
        {
            await _module.InvokeVoidAsync("initialize", _sentinelRef, _dotNetRef);
            _initialized = true;
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore) return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            if (_initialized)
            {
                try
                {
                    await _module.InvokeVoidAsync("dispose", _sentinelRef);
                }
                catch (JSDisconnectedException) { }
            }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

